using Microsoft.AspNetCore.Components.Authorization;
using sv_bb4e78a7711d40a99811b83b9c07c384;
using sv_bb4e78a7711d40a99811b83b9c07c384.Client.Pages;
using sv_bb4e78a7711d40a99811b83b9c07c384.Components;

var builder = WebApplication.CreateBuilder(args);

// Add services to the container.
builder.Services.AddRazorComponents()
    .AddInteractiveServerComponents()
    .AddInteractiveWebAssemblyComponents();

builder.Services.AddScoped<AuthenticationStateProvider, HardcodedAuthenticationStateProvider>();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthorization();
builder.Services.AddAuthenticationStateSerialization(options =>
    options.SerializeAllClaims = true);

var app = builder.Build();

arguments.file_text:
@page "/profile"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Profile</PageTitle>

<h1>Profile</h1>

<AuthorizeView>
    <Authorized>
        <p><strong>Name:</strong> @context.User.Identity?.Name</p>

        <h2>Roles</h2>
        <ul>
            @foreach (var role in context.User.Claims
                .Where(c => c.Type == System.Security.Claims.ClaimTypes.Role)
                .Select(c => c.Value))
            {
                <li>@role</li>
            }
        </ul>
    </Authorized>
</AuthorizeView>

@page "/editor"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Editor")]

<PageTitle>Editor</PageTitle>

<h1>Editor</h1>

<p>Welcome to the editor page. You have the <strong>Editor</strong> role.</p>

@page "/viewer"
@rendermode InteractiveAuto
@attribute [Authorize]

<PageTitle>Viewer</PageTitle>

<h1>Viewer</h1>

<p>This page is accessible to any authenticated user.</p>

